using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    unordered_map<long long, vector<vector<long long>>> graph;
    for (const auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long start = edge[2];
        long long end = edge[3];
        graph[u].push_back({v, start, end});
    }

    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;
    pq.push({0, 0});

    while (!pq.empty()) {
        auto current = pq.top();
        pq.pop();
        long long time = current.first;
        long long u = current.second;

        if (u == n - 1) {
            return time;
        }

        if (time > dist[u]) {
            continue;
        }

        for (const auto& edge : graph[u]) {
            long long v = edge[0];
            long long start = edge[1];
            long long end = edge[2];

            if (time > end) {
                continue;
            }

            long long arrival_time = max(time, start) + 1;
            if (arrival_time < dist[v]) {
                dist[v] = arrival_time;
                pq.push({arrival_time, v});
            }
        }
    }

    return -1;
}

