use std::cmp::Reverse;

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut graph: Vec<Vec<(usize, i64, i64)>> = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let start = edge[2];
        let end = edge[3];
        graph[u].push((v, start, end));
    }

    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;
    let mut heap = BinaryHeap::new();
    heap.push(Reverse((0, 0)));

    while let Some(Reverse((time, u))) = heap.pop() {
        if u == n - 1 {
            return time;
