        if time > dist[u] {
            continue;
        }
        for &(v, start, end) in &graph[u] {
            if time > end {
                continue;
            }
            let arrival_time = std::cmp::max(time, start) + 1;
            if arrival_time < dist[v] {
                dist[v] = arrival_time;
                heap.push(Reverse((arrival_time, v)));
            }
        }
    }

    -1
}
